// Mark incoming companies as new and prepare for dedup
// v8.3: Support for rescore mode - bypass dedup if _isRescore or _updateRecordId is set
const companies = $('Execute Workflow Trigger').all();
return companies.map(item => {
  const company = item.json;
  const name = company.company_name || company['Company Name'] || '';
  const source = company.source || company['VC Firm'] || 'Unknown';

  // Check if this is a rescore request (has existing record ID)
  const isRescore = company._isRescore === true || !!company._updateRecordId;

  return { 
    json: { 
      ...company, 
      _isNewCompany: !isRescore,
      _isRescore: isRescore,
      // Prepare dedup check data
      _dedupInput: {
        company: name,
        title: '',
        source: source,
        recordType: 'company'
      }
    } 
  };
});

// v9 Phase 0: Entity Validation
// Catch non-companies before enrichment wastes API calls

const items = $input.all();

// Entity validation patterns - signals this is NOT a company
const INVALID_ENTITY_SIGNALS = [
  /podcast/i, /blog/i, /newsletter/i, /media company/i,
  /student.*team/i, /university.*lab/i, /research.*group/i,
  /nonprofit/i, /non-profit/i, /foundation/i,
  /association/i, /coalition/i, /consortium/i,
  /accelerator program/i, /incubator program/i,
  /venture studio/i, /vc firm/i, /venture capital/i,
  /angel network/i, /investment firm/i
];

// URL TLD patterns that suggest non-company
const INVALID_URL_PATTERNS = [
  /\.org(?:\/|$)/i,
  /\.edu(?:\/|$)/i,
  /\.gov(?:\/|$)/i
];

// Signals this IS a valid company
const VALID_COMPANY_SIGNALS = [
  /\binc\.?\b/i, /\bllc\b/i, /\bcorp\.?\b/i, /\bltd\.?\b/i,
  /founded in \d{4}/i, /raised \$[\d.]+/i, /series [a-d]/i,
  /\d+ employees/i, /hiring/i, /careers page/i,
  /\bproduct\b/i, /\bplatform\b/i, /\bsaas\b/i, /\bsoftware\b/i,
  /customers include/i, /clients include/i,
  /b2b/i, /enterprise/i
];

return items.map(item => {
  const company = item.json;
  const name = company.company_name || company['Company Name'] || '';
  const url = company.company_url || company['Company URL'] || '';
  const description = company.description || company['Company Description'] || '';
  const textToCheck = `${name} ${description}`;

  // Check for invalid entity signals in name/description
  const invalidSignals = INVALID_ENTITY_SIGNALS.filter(p => p.test(textToCheck));

  // Check URL separately for TLD patterns
  const invalidUrlSignals = INVALID_URL_PATTERNS.filter(p => p.test(url));

  const hasInvalidSignals = invalidSignals.length > 0 || invalidUrlSignals.length > 0;

  // Check for valid company signals
  const validSignals = VALID_COMPANY_SIGNALS.filter(p => p.test(textToCheck));
  const hasValidSignals = validSignals.length > 0;

  // Entity is valid if:
  // - Has no invalid signals, OR
  // - Has invalid signals but also has valid company signals (override)
  const isValidEntity = !hasInvalidSignals || hasValidSignals;

  let entityValidationReason = null;
  if (!isValidEntity) {
    const allInvalid = [...invalidSignals, ...invalidUrlSignals];
    const matchedPatterns = allInvalid.map(p => p.toString().replace(/\/[gi]*/g, '').replace(/\(.*\)/g, '')).join(', ');
    entityValidationReason = `Invalid entity detected: ${matchedPatterns.substring(0, 100)}`;
  }

  return {
    json: {
      ...company,
      _isValidEntity: isValidEntity,
      _entityValidationReason: entityValidationReason
    }
  };
});

// Prepare invalid entity for DQ
const item = $json;
const reason = item._entityValidationReason || 'Invalid entity (media/podcast/nonprofit)';

return {
  json: {
    ...item,
    company_name: item.company_name || item['Company Name'] || '',
    company_url: item.company_url || item['Company URL'] || '',
    source: item.source || item['VC Firm'] || 'Unknown',
    disqualify_reasons: reason,
    status: 'Auto-Disqualified',
    total_score: 0
  }
};

// Prepare dedup registration for invalid entity records
const airtableRecord = $json;
let inputData = {};
try { inputData = $('Prep Invalid Entity').item?.json || {}; } catch(e) { inputData = {}; }

const normalize = (str) => str ? str.toLowerCase().replace(/[^a-z0-9]/g, '').trim() : '';
const company = inputData.company_name || '';
const key = `company:${normalize(company)}`;

return {
  json: {
    key: key,
    company: company,
    title: '',
    source: inputData.source || 'Unknown',
    recordType: 'company',
    airtableRecordId: airtableRecord.id
  }
};

// Log skipped duplicates for monitoring
const items = $input.all();
return items.map(item => {
  const dedupResult = item.json;
  return {
    json: {
      _skipped: true,
      _skipReason: 'cross_source_duplicate',
      _existingRecordId: dedupResult.existingRecordId,
      _allSources: dedupResult.allSources,
      _key: dedupResult.key,
      company_name: dedupResult._originalInput?.company,
      source: dedupResult._originalInput?.source
    }
  };
});

// Restore original company data for non-duplicates
const items = $input.all();
let markNewItems = [];
try { markNewItems = $('Mark as New & Prep Dedup').all(); } catch(e) { markNewItems = []; }

return items.map((item, index) => {
  const dedupResult = item.json;
  // Find matching original item by company name
  const companyName = dedupResult._originalInput?.company || '';
  const original = markNewItems.find(m => 
    (m.json.company_name || m.json['Company Name'] || '') === companyName
  );

  if (original) {
    return {
      json: {
        ...original.json,
        _dedupKey: dedupResult.key
      }
    };
  }

  // Fallback if no match
  return {
    json: {
      company_name: companyName,
      source: dedupResult._originalInput?.source,
      _dedupKey: dedupResult.key,
      _isNewCompany: true
    }
  };
});

const allItems = $input.all();
const newCompanies = [];
const existingRecords = [];

for (const item of allItems) {
  if (item.json._isNewCompany) {
    newCompanies.push(item);
  } else if (item.json.fields && item.json.fields['Company Name']) {
    existingRecords.push(item);
  } else if (item.json.id && item.json['Company Name']) {
    existingRecords.push({ json: { id: item.json.id, fields: item.json } });
  }
}

const normalize = (str) => str ? String(str).toLowerCase().replace(/[^a-z0-9]/g, '').trim() : '';

const existingMap = new Map();
for (const item of existingRecords) {
  const fields = item.json.fields || item.json;
  const name = fields['Company Name'] || '';
  const url = fields['Company URL'] || '';
  const recordId = item.json.id;
  if (name) {
    existingMap.set(normalize(name), { id: recordId, hasUrl: !!url && url.length > 0 });
  }
}

const uniqueCompanies = [];
const addedNames = new Set();

for (const company of newCompanies) {
  const name = company.json.company_name || company.json['Company Name'];
  const newUrl = company.json.company_url || company.json['Company URL'] || '';
  if (!name) continue;

  const normalizedName = normalize(name);
  if (!normalizedName || addedNames.has(normalizedName)) continue;

  const existing = existingMap.get(normalizedName);

  if (existing) {
    if (!existing.hasUrl && newUrl) {
      addedNames.add(normalizedName);
      const cleanCompany = { ...company.json };
      delete cleanCompany._isNewCompany;
      cleanCompany._updateRecordId = existing.id;
      uniqueCompanies.push({ json: cleanCompany });
    }
    continue;
  }

  addedNames.add(normalizedName);
  const cleanCompany = { ...company.json };
  delete cleanCompany._isNewCompany;
  uniqueCompanies.push({ json: cleanCompany });
}

if (uniqueCompanies.length === 0) {
  return [{ json: { _empty: true, _message: 'No new companies found' } }];
}

return uniqueCompanies;

// v8.4.14: Add __RID__ encoding for bulletproof _updateRecordId preservation
const items = $input.all();
return items.map(item => {
  const company = item.json;
  const name = company.company_name || company['Company Name'] || '';
  const updateRecordId = company._updateRecordId || '';
  // Encode record ID in query - Brave echoes this back in query.original for recovery
  const searchQuery = '"' + name + '" company funding employees series startup' + (updateRecordId ? ' __RID__' + updateRecordId + '__RID__' : '');
  return { json: { ...company, searchQuery } };
});

// v9: FULL REDESIGN - Enhanced enrichment with new detection patterns
// Includes: Better acquisition detection, GTM motion, software-first check, pre-sales detection, stale signals

const braveResponse = $json;
const companyDataItems = $('Build Search Query').all();

// Extract _updateRecordId from query.original (__RID__ encoding)
let extractedRecordId = null;
const queryOriginal = braveResponse?.query?.original || '';
const ridMatch = queryOriginal.match(/__RID__([^_]+)__RID__/);
if (ridMatch) extractedRecordId = ridMatch[1];

const currentIndex = typeof $itemIndex !== 'undefined' ? $itemIndex : 0;
const companyDataItem = companyDataItems[currentIndex]?.json || companyDataItems[0]?.json || {};

// v9: Get entity validation from Validate Entity node
let isValidEntity = true;
let entityValidationReason = null;
try {
  const validateItems = $('Validate Entity').all();
  const validateItem = validateItems[currentIndex]?.json || validateItems[0]?.json || {};
  isValidEntity = validateItem._isValidEntity !== false;
  entityValidationReason = validateItem._entityValidationReason || null;
} catch(e) { /* Validate Entity may not exist in rescore mode */ }

// Expanded PE/Growth Equity firm list (29+ firms)
const peFirms = [
  'Vista Equity', 'Thoma Bravo', 'KKR', 'Blackstone', 'TPG', 'Carlyle',
  'Bain Capital', 'Silver Lake', 'Francisco Partners', 'Accel-KKR',
  'LLR Partners', 'Warburg Pincus', 'Apollo', 'Insight Partners', 'GTCR',
  'Clearlake', 'Welsh Carson', 'Providence Equity', 'Leonard Green',
  'Hellman & Friedman', 'Advent', 'Golden Gate Capital', 'TA Associates',
  'Brighton Park Capital', 'General Atlantic', 'Summit Partners', 'SoftBank Vision Fund',
  'EQT Partners', 'Permira', 'Jonas Software', 'Constellation Software', 'Volaris',
  'Harris Computer', 'Total Specific Solutions', 'N. Harris Computer',
  'Ares Management', 'Ares Capital', 'Spring Lake Equity', 'Vector Capital'
];

// Fortune 500 / Large Enterprise parent companies
const fortune500Parents = [
  'Microsoft', 'Google', 'Amazon', 'Apple', 'Meta', 'Salesforce', 'Oracle',
  'IBM', 'SAP', 'Adobe', 'Cisco', 'Intel', 'Dell', 'HP', 'VMware', 'ServiceNow',
  'Workday', 'Intuit', 'Autodesk', 'Splunk', 'Atlassian', 'Zendesk', 'HubSpot',
  'Twilio', 'Datadog', 'Snowflake', 'Crowdstrike', 'Palo Alto Networks',
  'UnitedHealth', 'CVS', 'Cigna', 'Anthem', 'Humana', 'Kaiser', 'Optum',
  'JPMorgan', 'Goldman Sachs', 'Morgan Stanley', 'Bank of America', 'Wells Fargo',
  'Accenture', 'Deloitte', 'McKinsey', 'BCG', 'Bain'
];

// Helper functions
const parseFundingAmount = (amountStr, unitStr) => {
  const amount = parseFloat(amountStr);
  const unit = unitStr.toLowerCase();
  if (unit === 'billion' || unit === 'b') return amount * 1000000000;
  if (unit === 'million' || unit === 'm') return amount * 1000000;
  if (unit === 'k' || unit === 'thousand') return amount * 1000;
  return amount;
};

const formatFunding = (numeric) => {
  if (numeric >= 1000000000) return `$${(numeric / 1000000000).toFixed(1)}B`;
  if (numeric >= 1000000) return `$${(numeric / 1000000).toFixed(1)}M`;
  if (numeric >= 1000) return `$${(numeric / 1000).toFixed(0)}K`;
  return `$${numeric}`;
};

const currentYear = new Date().getFullYear();

// v9 THRESHOLDS
const MAX_BELIEVABLE_FUNDING = 5000000000;
const HARD_FUNDING_CAP = 450000000;
const SOFT_FUNDING_CAP = 75000000;
const MAX_VALUATION = 500000000;
const MIN_EMPLOYEES = 15;
const HARD_EMPLOYEE_CAP = 150;
const SOFT_EMPLOYEE_CAP = 150;
const MIN_FOUNDED_YEAR = 2016;
const STALE_FUNDING_YEARS = 3; // v9: No funding in 3+ years = stale

const companyData = {
  company_name: companyDataItem.company_name || companyDataItem['Company Name'],
  company_url: companyDataItem.company_url || companyDataItem['Company URL'],
  description: companyDataItem.description || companyDataItem['Company Description'],
  source: companyDataItem.source || companyDataItem['VC Firm'] || 'Unknown',
  _dedupKey: companyDataItem._dedupKey,
  _updateRecordId: companyDataItem._updateRecordId
};

const searchResults = braveResponse?.web?.results || [];
const allText = searchResults.map(r => `${r.title || ''} ${r.description || ''}`).join(' ');

// === EXTRACT BASIC INFO ===
let employeeCount = null;
const empMatch = allText.match(/([\d,]+)\s*(?:to\s*[\d,]+)?\s*employees?/i);
if (empMatch) employeeCount = parseInt(empMatch[1].replace(/,/g, ''));

let fundingStage = null;
const stagePatterns = {
  'Series E': /Series\s*E/i,
  'Series D': /Series\s*D/i,
  'Series C': /Series\s*C/i,
  'Series B': /Series\s*B/i,
  'Series A': /Series\s*A/i,
  'Seed': /\bSeed\b/i
};
for (const [stage, pattern] of Object.entries(stagePatterns)) {
  if (pattern.test(allText)) { fundingStage = stage; break; }
}

// Funding extraction
let totalFunding = null, totalFundingRaw = null;
const fundingCandidates = [];
const contextualPatterns = [
  /(?:raised|secur(?:ed|es)|total funding of|funding of|announced)\s*\$([\d.]+)\s*(million|billion|M|B)/gi,
  /\$([\d.]+)\s*(million|billion|M|B)\s*(?:raised|funding|round|series)/gi
];
for (const pattern of contextualPatterns) {
  let match;
  while ((match = pattern.exec(allText)) !== null) {
    const numeric = parseFundingAmount(match[1], match[2]);
    if (numeric <= MAX_BELIEVABLE_FUNDING && numeric >= 100000) {
      fundingCandidates.push({ numeric, raw: formatFunding(numeric), priority: 1 });
    }
  }
}
if (fundingCandidates.length === 0) {
  const fallbackPattern = /\$([\d.]+)\s*(million|billion|M|B)/gi;
  let match;
  while ((match = fallbackPattern.exec(allText)) !== null) {
    const numeric = parseFundingAmount(match[1], match[2]);
    if (numeric <= MAX_BELIEVABLE_FUNDING && numeric >= 100000) {
      fundingCandidates.push({ numeric, raw: formatFunding(numeric), priority: 2 });
    }
  }
}
if (fundingCandidates.length > 0) {
  fundingCandidates.sort((a, b) => a.priority !== b.priority ? a.priority - b.priority : b.numeric - a.numeric);
  totalFunding = fundingCandidates[0].numeric;
  totalFundingRaw = fundingCandidates[0].raw;
}

// Valuation
let valuation = null, valuationRaw = null;
if (/unicorn/i.test(allText)) {
  valuation = 1000000000;
  valuationRaw = '$1.0B (unicorn)';
} else {
  const valuationPatterns = [
    /valued\s+at\s+\$([\d.]+)\s*(million|billion|M|B)/gi,
    /valuation\s+(?:of\s+)?\$([\d.]+)\s*(million|billion|M|B)/gi
  ];
  for (const pattern of valuationPatterns) {
    let match;
    while ((match = pattern.exec(allText)) !== null) {
      const numeric = parseFundingAmount(match[1], match[2]);
      if (numeric > (valuation || 0)) {
        valuation = numeric;
        valuationRaw = formatFunding(numeric);
      }
    }
  }
}

// Founded year
let foundedYear = null;
const foundMatch = allText.match(/(?:founded|established|since)\s*(?:in)?\s*(\d{4})/i);
if (foundMatch) foundedYear = parseInt(foundMatch[1]);

// === v9: ENHANCED ACQUISITION DETECTION ===
let isAcquired = false;
let acquiredBy = null;
let acquiredByPE = false;

const acquirePatterns = [
  /acquired\s+by\s+([A-Z][a-zA-Z0-9\s&]+)/i,
  /bought\s+by\s+([A-Z][a-zA-Z0-9\s&]+)/i,
  /merged\s+with\s+([A-Z][a-zA-Z0-9\s&]+)/i,
  /part\s+of\s+([A-Z][a-zA-Z0-9\s&]+(?:Group|Holdings|Capital|Inc|Corp))/i,
  /subsidiary\s+of\s+([A-Z][a-zA-Z0-9\s&]+)/i,
  /now\s+owned\s+by\s+([A-Z][a-zA-Z0-9\s&]+)/i,
  /joined\s+([A-Z][a-zA-Z0-9\s&]+)\s+family/i,
  /portfolio\s+company\s+of\s+([A-Z][a-zA-Z0-9\s&]+(?:Capital|Partners|Equity)?)/i
];

for (const pattern of acquirePatterns) {
  const match = allText.match(pattern);
  if (match) {
    isAcquired = true;
    acquiredBy = match[1]?.trim().substring(0, 50) || 'Unknown';
    // Check if acquirer is PE firm
    acquiredByPE = peFirms.some(pe => new RegExp(pe, 'i').test(acquiredBy));
    break;
  }
}
if (!isAcquired && /\b(was acquired|has been acquired|acquired in \d{4}|formerly|shut down|shuttered|defunct|no longer operating)\b/i.test(allText)) {
  isAcquired = true;
}

// === PE and Fortune 500 Detection ===
const isPEBacked = peFirms.some(f => new RegExp(f, 'i').test(allText));
const peBackerFound = peFirms.find(f => new RegExp(f, 'i').test(allText)) || null;

const isFortune500Subsidiary = fortune500Parents.some(parent => {
  const patterns = [
    new RegExp(`subsidiary of ${parent}`, 'i'),
    new RegExp(`owned by ${parent}`, 'i'),
    new RegExp(`part of ${parent}`, 'i'),
    new RegExp(`a ${parent} company`, 'i')
  ];
  return patterns.some(p => p.test(allText));
});
const fortune500Parent = fortune500Parents.find(parent => {
  return new RegExp(`subsidiary of ${parent}|owned by ${parent}|part of ${parent}`, 'i').test(allText);
}) || null;

const isPublic = /\b(NYSE|NASDAQ|publicly traded|IPO|stock ticker|went public|NYSE:|NASDAQ:)\b/i.test(allText);

// === v9: GEOGRAPHY DETECTION (Enhanced) ===
const usHQPatterns = /\b(headquartered in (?:the )?(?:US|USA|United States)|based in (?:San Francisco|New York|NYC|Boston|Austin|Seattle|LA|Los Angeles|Chicago|Denver|Atlanta|Miami|Palo Alto|Silicon Valley)|California|Texas|Massachusetts|New York|Washington)\b/i;
const usSignals = /\b(San Francisco|NYC|Boston|Austin|Seattle|LA|Chicago|Denver|Atlanta|Palo Alto|Mountain View|Menlo Park|Silicon Valley|US-based|USA)\b/i;
const nonUSHQPatterns = /\b(headquartered in (?!.*(?:US|USA|United States))|based in (?:London|Berlin|Paris|Tel Aviv|Singapore|Sydney|Toronto|Mumbai|Bangalore|Amsterdam|Dublin|Stockholm))\b/i;
const nonUSSignals = /\b(London|Berlin|Paris|Tel Aviv|Singapore|Toronto|Sydney|Mumbai|Bangalore|Amsterdam|Dublin|Stockholm|Zurich|Tokyo|Seoul|UK-based|EU-based|European|Israeli|EMEA|APAC)\b/i;

const isUSBased = (usHQPatterns.test(allText) || usSignals.test(allText)) && !nonUSHQPatterns.test(allText);
const isNonUSBased = (nonUSHQPatterns.test(allText) || nonUSSignals.test(allText)) && !usHQPatterns.test(allText);
const geographyUncertain = !isUSBased && !isNonUSBased;

// === v9: GTM MOTION EXTRACTION ===
const PLG_SIGNALS = [
  /free (?:tier|plan|trial)/i,
  /self[\s-]?serve/i,
  /product[\s-]?led/i,
  /no[\s-]?touch/i,
  /freemium/i,
  /community[\s-]?edition/i,
  /open[\s-]?source/i,
  /viral growth/i,
  /sign up free/i,
  /try for free/i
];

const ENTERPRISE_GTM_SIGNALS = [
  /enterprise (?:sales|team|customers)/i,
  /account (?:executive|manager)/i,
  /sales[\s-]?led/i,
  /high[\s-]?touch/i,
  /implementation (?:team|services)/i,
  /customer success (?:team|manager)/i,
  /onboarding (?:team|specialist)/i,
  /contract (?:value|ACV)/i,
  /\$[\d,]+k\s*(?:acv|arr)/i,
  /enterprise[\s-]?grade/i
];

const plgSignalCount = PLG_SIGNALS.filter(p => p.test(allText)).length;
const enterpriseSignalCount = ENTERPRISE_GTM_SIGNALS.filter(p => p.test(allText)).length;
const isPLGDominant = plgSignalCount >= 3 && enterpriseSignalCount < 2;
const hasEnterpriseMotion = enterpriseSignalCount >= 2;
const gtmMotion = isPLGDominant ? 'plg-dominant' : (hasEnterpriseMotion ? 'enterprise' : 'unknown');

// === v9: SOFTWARE-FIRST CHECK ===
const SERVICES_SIGNALS = [
  /(?:creative|design) (?:services|studio|agency)/i,
  /(?:managed|professional) services/i,
  /\bconsulting\b/i,
  /\bstaffing\b/i, /\brecruiting agency\b/i,
  /(?:photo|video) (?:shoot|production)/i,
  /virtual (?:studio|assistant)/i,
  /on[\s-]?demand (?:labor|workforce)/i,
  /human[\s-]?powered/i,
  /direct (?:care|healthcare) services/i,
  /virtual care (?:services|provider)/i,
  /(?:insurance|benefits) brokerage/i,
  /(?:data|analytics) services hybrid/i
];

const HARDWARE_AS_SAAS_SIGNALS = [
  /(?:hardware|device)\s*(?:plus|with|and)\s*(?:software|cloud)/i,
  /(?:sensor|camera|scanner)\s*(?:platform|dashboard)/i,
  /physical (?:product|device)/i,
  /(?:installation|deployment) (?:required|team)/i
];

const isServicesBusiness = SERVICES_SIGNALS.some(p => p.test(allText));
const isHardwareMasquerading = HARDWARE_AS_SAAS_SIGNALS.some(p => p.test(allText));
const isSoftwareFirst = !isServicesBusiness && !isHardwareMasquerading;

// === v9: PRE-SALES FUNCTION DETECTION (v9.1: expanded patterns) ===
const PRESALES_PRODUCT_SIGNALS = [
  /presales?\s*(?:platform|tool|software|solution|automation)/i,
  /\bpre-sales\s*(?:platform|tool|software|solution)/i,
  /demo\s*(?:automation|platform|software|environment)/i,
  /sales\s*(?:enablement|engagement)\s*(?:platform|software)/i,
  /configure[\s-]?price[\s-]?quote/i,
  /\bCPQ\b/i,
  /proof[\s-]?of[\s-]?concept\s*(?:automation|platform)/i,
  /technical\s*win\s*platform/i,
  /solution\s*engineering\s*platform/i,
  /sales\s*engineer\s*(?:platform|tool)/i,
  /presales?\s*intelligence/i,
  /buyer\s*enablement/i,
  /\bpresales?\b.*?\bAI\b/i,
  /AI.*?\bpresales?\b/i
];

const isPresalesCompany = PRESALES_PRODUCT_SIGNALS.some(p => p.test(allText));

// === v9: STALE COMPANY DETECTION (Enhanced) ===
const SHRINKING_SIGNALS = [
  /\blayoff/i, /\blaid off/i, /workforce reduction/i,
  /\bdownsiz/i, /\brestructur/i, /right[\s-]?siz/i,
  /headcount (?:reduction|cut)/i,
  /(?:reduced|cut) (?:\d+%|\d+ (?:employees|staff))/i,
  /letting go of/i
];

const CONTRACTION_SIGNALS = [
  /\bpivot/i, /wind[\s-]?down/i, /acqui[\s-]?hire/i,
  /\bstruggling\b/i, /\bchallenges\b/i, /\bdifficult\b/i,
  /runway concerns/i, /cash flow issues/i
];

const hasShrinkingSignals = SHRINKING_SIGNALS.some(p => p.test(allText));
const hasContractionSignals = CONTRACTION_SIGNALS.some(p => p.test(allText));

// Estimate funding age (v9.1: improved patterns)
let fundingAgeYears = null;
let lastFundingYear = null;
const fundingYearPatterns = [
  /series\s*[a-e]\s*(?:round\s*)?(?:in\s*)?(20\d{2})/i,
  /raised.*?(20\d{2})/i,
  /(20\d{2}).*?series\s*[a-e]/i,
  /(?:funding|round).*?(20\d{2})/i,
  /(?:may|june|july|aug|sep|oct|nov|dec|jan|feb|mar|apr).*?(20\d{2}).*?(?:series|raised|funding)/i
];
for (const pattern of fundingYearPatterns) {
  const match = allText.match(pattern);
  if (match) {
    const year = parseInt(match[1]);
