// Prepare dedup registration for evaluated records
const airtableRecord = $json;
let parseData = {};
try { parseData = $('Check Job & Network Matches').item?.json || {}; } catch(e) { parseData = {}; }

const normalize = (str) => str ? str.toLowerCase().replace(/[^a-z0-9]/g, '').trim() : '';
const company = parseData.company_name || '';
const key = `company:${normalize(company)}`;

return {
  json: {
    key: key,
    company: company,
    title: '',
    source: parseData.source || 'Unknown',
    recordType: 'company',
    airtableRecordId: airtableRecord.id
  }
};

// v8.4.2: Transform field names for Airtable auto-mapping
const item = $json;
const status = item.hasCxJobPosting ? 'Immediate Action' : (item.hasNetworkConnection ? 'Network Lead' : item.status);
const nextSteps = item.hasCxJobPosting ? 'Apply Now - Active CX Role' : (item.hasNetworkConnection ? 'Reach Out to Connection' : item.next_steps);

return {
  json: {
    // Record ID for update - used by node's id parameter, not sent to Airtable
    _updateRecordId: item._updateRecordId,
    // Airtable column names
    'Company URL': item.company_url || '',
